+function resolveAndApplyOutboundThreadId(
+  params: Record<string, unknown>,
+  ctx: {
+    channel: ChannelId;
+    to: string;
+    toolContext?: ChannelThreadingToolContext;
+    allowSlackAutoThread: boolean;
